// Inputs: usage trend, ticket count + sentiment proxy, gong calls, engagement
// Output: { riskScore, riskLevel, signals[], renewal }

const renewal = $('Loop per Renewal').item.json;
const usage = $('Fetch Mixpanel Usage Trend').item.json;
const tickets = $('Fetch Zendesk Tickets').item.json;
const calls = $('Fetch Gong Calls (90d)').item.json;
const engagement = $('Fetch Champion Engagement').item.json;

// --- USAGE TREND (35%) ---
const usageBuckets = Array.isArray(usage) ? usage : (usage?.data || []);
let usageScore = 0;
if (usageBuckets.length >= 60) {
  const recent = usageBuckets.slice(-30).reduce((s, b) => s + (b.value || b[1] || 0), 0);
  const prior = usageBuckets.slice(-60, -30).reduce((s, b) => s + (b.value || b[1] || 0), 0);
  const change = prior === 0 ? 0 : ((recent - prior) / prior) * 100;
  if (change < -50) usageScore = 35;
  else if (change < -30) usageScore = 25;
  else if (change < -15) usageScore = 15;
  else if (change < 0) usageScore = 5;
}

// --- SUPPORT TICKETS (25%) ---
const ticketArr = Array.isArray(tickets) ? tickets : (tickets?.results || []);
const escalated = ticketArr.filter(t => (t.priority === 'urgent' || t.priority === 'high') || t.tags?.includes('escalation')).length;
let ticketScore = 0;
if (escalated >= 5) ticketScore = 25;
else if (escalated >= 3) ticketScore = 18;
else if (escalated >= 1) ticketScore = 10;

// --- CHAMPION ENGAGEMENT (20%) ---
const engagementArr = Array.isArray(engagement) ? engagement : (engagement?.records || []);
let engagementScore = 0;
if (engagementArr.length === 0) {
  engagementScore = 20;
} else {
  const lastTouch = new Date(engagementArr[0].ActivityDate);
  const daysSince = (Date.now() - lastTouch.getTime()) / (1000 * 60 * 60 * 24);
  if (daysSince > 45) engagementScore = 20;
  else if (daysSince > 30) engagementScore = 14;
  else if (daysSince > 14) engagementScore = 7;
}

// --- CALL SENTIMENT (20%) ---
const callArr = calls?.calls || [];
const recentCalls = callArr.slice(0, 3);
let callScore = 0;
if (recentCalls.length === 0) {
  callScore = 12; // no recent calls is itself a risk
} else {
  // Use Gong tracker hits as proxy for sentiment
  const negativeTrackers = recentCalls.flatMap(c => c.content?.trackers?.filter(t => /churn|cancel|frustrated|concern|issue/i.test(t.name)) || []);
  if (negativeTrackers.length >= 5) callScore = 20;
  else if (negativeTrackers.length >= 2) callScore = 12;
}

const riskScore = usageScore + ticketScore + engagementScore + callScore;
const riskLevel = riskScore >= 65 ? 'HIGH' : riskScore >= 40 ? 'MEDIUM' : 'LOW';
const daysToRenewal = Math.ceil((new Date(renewal.CloseDate) - Date.now()) / (1000 * 60 * 60 * 24));

return {
  json: {
    renewal,
    riskScore,
    riskLevel,
    daysToRenewal,
    signals: { usageScore, ticketScore, engagementScore, callScore },
    rawData: { usage, tickets, calls, engagement }
  }
};

